  1→import {
  2→  BedrockRuntimeClient,
  3→  ConverseStreamCommand,
  4→  type Message,
  5→  type ContentBlock,
  6→  type GuardrailConfiguration,
  7→} from "@aws-sdk/client-bedrock-runtime";
  8→
  9→// Uses default AWS credentials chain (profile, env vars, IAM role)
 10→const client = new BedrockRuntimeClient({
 11→  region: process.env.AWS_REGION || "us-east-1",
 12→});
 13→
 14→const MODEL_ID = process.env.BEDROCK_MODEL_ID || "us.anthropic.claude-opus-4-6-v1";
 15→
 16→interface BedrockStreamOptions {
 17→  systemPrompt: string;
 18→  messages: { role: "user" | "assistant"; content: string }[];
 19→  guardrailId?: string;
 20→  guardrailVersion?: string;
 21→}
 22→
 23→export async function* streamBedrockResponse(
 24→  options: BedrockStreamOptions
 25→): AsyncGenerator<
 26→  { type: "text"; text: string } | { type: "guard"; action: string; message: string },
 27→  void,
 28→  unknown
 29→> {
 30→  const { systemPrompt, messages, guardrailId, guardrailVersion } = options;
 31→
 32→  const bedrockMessages: Message[] = messages.map((m) => ({
 33→    role: m.role,
 34→    content: [{ text: m.content } as ContentBlock],
 35→  }));
 36→
 37→  const guardrailConfig: GuardrailConfiguration | undefined =
 38→    guardrailId && guardrailVersion
 39→      ? {
 40→          guardrailIdentifier: guardrailId,
 41→          guardrailVersion: guardrailVersion,
 42→        }
 43→      : undefined;
 44→
 45→  const command = new ConverseStreamCommand({
 46→    modelId: MODEL_ID,
 47→    system: [{ text: systemPrompt }],
 48→    messages: bedrockMessages,
 49→    inferenceConfig: {
 50→      maxTokens: 4096,
 51→      temperature: 0.3,
 52→    },
 53→    ...(guardrailConfig && { guardrailConfig: guardrailConfig }),
 54→  });
 55→
 56→  const response = await client.send(command);
 57→
 58→  if (!response.stream) {
 59→    throw new Error("No stream in Bedrock response");
 60→  }
 61→
 62→  for await (const event of response.stream) {
 63→    if (event.contentBlockDelta?.delta?.text) {
 64→      yield { type: "text", text: event.contentBlockDelta.delta.text };
 65→    }
 66→
 67→    // Check if guardrail intervened
 68→    if (event.metadata?.trace?.guardrail?.inputAssessment) {
 69→      const assessment = event.metadata.trace.guardrail.inputAssessment;
 70→      const assessmentValues = Object.values(assessment);
 71→      for (const a of assessmentValues) {
 72→        if (a.topicPolicy?.topics) {
 73→          for (const topic of a.topicPolicy.topics) {
 74→            if (topic.action === "BLOCKED") {
 75→              yield {
 76→                type: "guard",
 77→                action: "BLOCKED",
 78→                message: `I can only analyze the reviews that have been loaded into this session. I'm not able to help with topics related to "${topic.name}". Feel free to ask me anything about the ingested reviews!`,
 79→              };
 80→              return;
 81→            }
 82→          }
 83→        }
 84→      }
 85→    }
 86→
 87→    if (event.metadata?.trace?.guardrail?.outputAssessments) {
 88→      const assessments = event.metadata.trace.guardrail.outputAssessments;
 89→      for (const assessmentList of Object.values(assessments)) {
 90→        for (const a of assessmentList as Array<Record<string, unknown>>) {
 91→          const topicPolicy = a.topicPolicy as { topics?: Array<{ action: string; name: string }> } | undefined;
 92→          if (topicPolicy?.topics) {
 93→            for (const topic of topicPolicy.topics) {
 94→              if (topic.action === "BLOCKED") {
 95→                yield {
 96→                  type: "guard",
 97→                  action: "BLOCKED",
 98→                  message: `I can only analyze the reviews that have been loaded into this session. I'm not able to help with topics related to "${topic.name}". Feel free to ask me anything about the ingested reviews!`,
 99→                };
100→                return;
101→              }
102→            }
103→          }
104→        }
105→      }
106→    }
107→  }
108→}
