 1→import {
 2→  ComprehendClient,
 3→  BatchDetectSentimentCommand,
 4→} from "@aws-sdk/client-comprehend";
 5→import { Review, SentimentResult } from "@/types";
 6→
 7→// Uses default AWS credentials chain (profile, env vars, IAM role)
 8→const client = new ComprehendClient({
 9→  region: process.env.AWS_REGION || "us-east-1",
10→});
11→
12→export async function analyzeSentiment(
13→  reviews: Review[]
14→): Promise<Review[]> {
15→  // Comprehend batch limit is 25 documents, each max 5000 bytes
16→  const batchSize = 25;
17→  const enrichedReviews = [...reviews];
18→
19→  // Build all batch promises up front so they run in parallel
20→  const batchPromises: Promise<void>[] = [];
21→
22→  for (let i = 0; i < reviews.length; i += batchSize) {
23→    const batchStart = i;
24→    const batch = reviews.slice(batchStart, batchStart + batchSize);
25→    const texts = batch.map((r) => {
26→      const text = `${r.title} ${r.body}`.slice(0, 4900);
27→      // Comprehend requires non-empty text
28→      return text.trim() || "No content";
29→    });
30→
31→    batchPromises.push(
32→      (async () => {
33→        try {
34→          const command = new BatchDetectSentimentCommand({
35→            TextList: texts,
36→            LanguageCode: "en",
37→          });
38→
39→          const response = await client.send(command);
40→
41→          if (response.ResultList) {
42→            for (const result of response.ResultList) {
43→              if (result.Index !== undefined && result.Sentiment) {
44→                const reviewIndex = batchStart + result.Index;
45→                enrichedReviews[reviewIndex] = {
46→                  ...enrichedReviews[reviewIndex],
47→                  sentiment: {
48→                    label: result.Sentiment as SentimentResult["label"],
49→                    score:
50→                      result.SentimentScore?.[
51→                        (result.Sentiment.charAt(0) +
52→                          result.Sentiment.slice(1).toLowerCase()) as keyof typeof result.SentimentScore
53→                      ] || 0,
54→                  },
55→                };
56→              }
57→            }
58→          }
59→        } catch (error) {
60→          console.error("Comprehend batch sentiment error:", error);
61→          // Fallback: use rating-based sentiment
62→          for (let j = 0; j < batch.length; j++) {
63→            const reviewIndex = batchStart + j;
64→            const rating = batch[j].rating;
65→            enrichedReviews[reviewIndex] = {
66→              ...enrichedReviews[reviewIndex],
67→              sentiment: {
68→                label: rating >= 4 ? "POSITIVE" : rating <= 2 ? "NEGATIVE" : "NEUTRAL",
69→                score: 0.8,
70→              },
71→            };
72→          }
73→        }
74→      })()
75→    );
76→  }
77→
78→  await Promise.all(batchPromises);
79→  return enrichedReviews;
80→}
