 18→// --- Shared Apify helpers ---
 19→
 20→interface ApifyRunResponse {
 21→  data: {
 22→    id: string;
 23→    status: string;
 24→    defaultDatasetId: string;
 25→  };
 26→}
 27→
 28→async function apifyFetch(path: string, options?: RequestInit): Promise<Response> {
 29→  const token = process.env.APIFY_API_TOKEN;
 30→  if (!token) {
 31→    throw new Error("APIFY_API_TOKEN not configured");
 32→  }
 33→  const url = `${APIFY_BASE_URL}${path}`;
 34→  const headers = new Headers(options?.headers);
 35→  headers.set("Authorization", `Bearer ${token}`);
 36→  return fetch(url, { ...options, headers });
 37→}
 38→
 39→async function waitForRun(runId: string, actorId: string, timeoutMs = 120000): Promise<ApifyRunResponse["data"]> {
 40→  const start = Date.now();
 41→  while (Date.now() - start < timeoutMs) {
 42→    const res = await apifyFetch(`/acts/${actorId}/runs/${runId}`);
 43→    const data = (await res.json()) as ApifyRunResponse;
 44→    if (data.data.status === "SUCCEEDED") return data.data;
 45→    if (data.data.status === "FAILED" || data.data.status === "ABORTED") {
 46→      throw new Error(`Apify run ${data.data.status.toLowerCase()}`);
 47→    }
 48→    await new Promise((r) => setTimeout(r, 3000));
 49→  }
 50→  throw new Error("Apify run timed out");
 51→}
 52→
 53→async function startAndCollect(actorId: string, input: Record<string, unknown>): Promise<unknown[]> {
 54→  const startRes = await apifyFetch(`/acts/${actorId}/runs`, {
 55→    method: "POST",
 56→    headers: { "Content-Type": "application/json" },
 57→    body: JSON.stringify(input),
 58→  });
 59→
 60→  if (!startRes.ok) {
 61→    const err = await startRes.text();
 62→    throw new Error(`Failed to start Apify actor: ${err}`);
 63→  }
 64→
 65→  const startData = (await startRes.json()) as ApifyRunResponse;
 66→  const run = await waitForRun(startData.data.id, actorId);
 67→
 68→  const datasetRes = await apifyFetch(`/datasets/${run.defaultDatasetId}/items?format=json`);
 69→  if (!datasetRes.ok) {
 70→    throw new Error("Failed to fetch Apify dataset results");
 71→  }
 72→
 73→  const items = (await datasetRes.json()) as unknown[];
 74→  if (!items || items.length === 0) {
 75→    throw new Error("No reviews found. The page may have no reviews or the scraper couldn't access them.");
 76→  }
 77→
 78→  return items;
 79→}
