 83→interface ApifyAmazonReview {
 84→  reviewTitle?: string;
 85→  reviewBody?: string;
 86→  ratingScore?: number;
 87→  reviewedIn?: string;
 88→  reviewerName?: string;
 89→  isVerified?: boolean;
 90→  date?: string;
