132→export async function scrapeAmazonReviews(url: string): Promise<ScrapeResult> {
133→  const asinMatch = url.match(/\/(?:dp|gp\/product|product-reviews)\/([A-Z0-9]{10})/);
134→  if (!asinMatch) {
135→    throw new Error("Could not extract Amazon product ID (ASIN) from URL. Please ensure it's a valid Amazon product URL.");
136→  }
137→
138→  const asin = asinMatch[1];
139→  const actorId = ACTOR_IDS.Amazon;
140→
141→  const overallPromise = scrapeOverallRating(asin);
142→
143→  const items = (await startAndCollect(actorId, {
144→    productUrls: [{ url: `https://www.amazon.com/dp/${asin}` }],
145→    maxReviews: 100,
146→    sort: "recent",
147→  })) as ApifyAmazonReview[];
148→
149→  const reviews: Review[] = items.map((item) => ({
150→    id: uuidv4(),
151→    rating: item.ratingScore || item.rating || item.stars || 0,
152→    title: (item.reviewTitle || item.title || "").trim(),
153→    body: (item.reviewBody || item.body || item.text || "").trim(),
154→    date: (item.reviewedIn || item.date || "").replace(/^Reviewed in .* on /, "").trim(),
155→    reviewer: (item.reviewerName || item.author || item.name || "Anonymous").trim(),
156→    verified: item.isVerified ?? item.verified ?? false,
157→  })).filter((r) => r.body || r.title);
158→
159→  const overall = await overallPromise;
160→  const productName = overall.productName || "Amazon Product " + asin;
161→
162→  return {
163→    reviews,
164→    productName,
165→    overallRating: overall.overallRating,
166→    totalGlobalRatings: overall.totalGlobalRatings,
167→  };
168→}
