170→// --- Google Maps ---
171→
172→interface ApifyGoogleMapsReview {
173→  text?: string;
174→  textTranslated?: string;
175→  stars?: number;
176→  publishedAtDate?: string;
177→  reviewerName?: string;
178→  isLocalGuide?: boolean;
179→}
180→
181→export async function scrapeGoogleMapsReviews(url: string): Promise<ScrapeResult> {
182→  if (!url.includes("google.com/maps") && !url.includes("maps.app.goo.gl")) {
183→    throw new Error("Please provide a valid Google Maps URL.");
184→  }
185→
186→  const actorId = ACTOR_IDS["Google Maps"];
187→
188→  const items = (await startAndCollect(actorId, {
189→    startUrls: [{ url }],
190→    maxReviews: 100,
191→    reviewsSort: "newest",
192→    language: "en",
193→    scrapeReviewerName: true,
194→  })) as ApifyGoogleMapsReview[];
195→
196→  const reviews: Review[] = items.map((item) => ({
197→    id: uuidv4(),
198→    rating: item.stars || 0,
199→    title: "",
200→    body: (item.textTranslated || item.text || "").trim(),
201→    date: item.publishedAtDate ? new Date(item.publishedAtDate).toLocaleDateString("en-US", { year: "numeric", month: "long", day: "numeric" }) : "",
202→    reviewer: (item.reviewerName || "Anonymous").trim(),
203→    verified: item.isLocalGuide ?? false,
204→  })).filter((r) => r.body);
205→
206→  // Extract place name from URL
207→  const nameMatch = url.match(/\/place\/([^/@]+)/);
208→  const productName = nameMatch ? decodeURIComponent(nameMatch[1]).replace(/\+/g, " ") : "Google Maps Place";
209→
210→  const totalRating = reviews.reduce((sum, r) => sum + r.rating, 0);
211→  const overallRating = reviews.length > 0 ? Math.round((totalRating / reviews.length) * 10) / 10 : undefined;
212→
213→  return {
214→    reviews,
215→    productName,
216→    overallRating,
217→    totalGlobalRatings: reviews.length,
218→  };
219→}
220→
221→// --- Platform dispatcher ---
222→
223→export async function scrapeReviews(platform: string, url: string): Promise<ScrapeResult> {
224→  switch (platform) {
225→    case "Amazon":
226→      return scrapeAmazonReviews(url);
227→    case "Google Maps":
228→      return scrapeGoogleMapsReviews(url);
229→    default:
230→      throw new Error(`URL scraping is not supported for ${platform}. Please use CSV upload.`);
231→  }
232→}
