  9→// Convert async generator to a ReadableStream using the pull pattern
 10→// (recommended by Next.js docs for proper chunk-by-chunk streaming)
 11→function iteratorToStream(
 12→  iterator: AsyncGenerator<Uint8Array, void, unknown>
 13→): ReadableStream<Uint8Array> {
 14→  return new ReadableStream({
 15→    async pull(controller) {
 16→      const { value, done } = await iterator.next();
 17→      if (done) {
 18→        controller.close();
 19→      } else {
 20→        controller.enqueue(value);
 21→      }
 22→    },
 23→  });
 24→}
