 26→export async function POST(request: NextRequest) {
 27→  try {
 28→    const { sessionId, message, history = [], sessionData } =
 29→      await request.json();
 30→
 31→    if (!sessionId || !message) {
 32→      return new Response(
 33→        JSON.stringify({ error: "sessionId and message are required" }),
 34→        { status: 400, headers: { "Content-Type": "application/json" } }
 35→      );
 36→    }
 37→
 38→    // Try in-memory store first; if missing, hydrate from client-provided sessionData
 39→    let session = getSession(sessionId);
 40→
 41→    if (!session && sessionData) {
 42→      // Basic validation: ensure sessionData has the expected shape
 43→      const reviews = Array.isArray(sessionData.reviews) ? sessionData.reviews : [];
 44→      const meta = sessionData.metadata;
 45→      if (
 46→        reviews.length > 0 &&
 47→        meta &&
 48→        typeof meta.platform === "string" &&
 49→        typeof meta.productName === "string" &&
 50→        typeof meta.totalReviews === "number"
 51→      ) {
 52→        const restored: ReviewSession = {
 53→          sessionId,
 54→          reviews: reviews.slice(0, 500), // Cap at 500 reviews to prevent abuse
 55→          metadata: meta,
 56→          analytics: sessionData.analytics,
 57→        };
 58→        setSession(sessionId, restored);
 59→        session = restored;
 60→      }
 61→    }
 62→
 63→    if (!session) {
 64→      return new Response(
 65→        JSON.stringify({
 66→          error: "Session not found. Please ingest reviews first.",
 67→        }),
 68→        { status: 404, headers: { "Content-Type": "application/json" } }
 69→      );
 70→    }
 71→
 72→    // Build system prompt with review context
 73→    const systemPrompt = buildSystemPrompt(session.metadata, session.reviews);
 74→
 75→    // Sanitize history: only allow valid roles and string content
 76→    const MAX_HISTORY_MESSAGES = 50;
 77→    const MAX_MESSAGE_LENGTH = 10_000;
 78→
 79→    const sanitizedHistory = (Array.isArray(history) ? history : [])
 80→      .slice(-MAX_HISTORY_MESSAGES)
 81→      .filter(
 82→        (h: unknown): h is { role: string; content: string } =>
 83→          typeof h === "object" &&
 84→          h !== null &&
 85→          typeof (h as Record<string, unknown>).role === "string" &&
 86→          typeof (h as Record<string, unknown>).content === "string" &&
 87→          ["user", "assistant"].includes((h as Record<string, unknown>).role as string)
 88→      )
 89→      .map((h) => ({
 90→        role: h.role as "user" | "assistant",
 91→        content: h.content.slice(0, MAX_MESSAGE_LENGTH),
 92→      }));
 93→
 94→    // Build conversation messages (include history for context)
 95→    const messages = [
 96→      ...sanitizedHistory,
 97→      { role: "user" as const, content: message.slice(0, MAX_MESSAGE_LENGTH) },
 98→    ];
 99→
100→    // Stream response using Bedrock with Guardrails
101→    const guardrailId = process.env.BEDROCK_GUARDRAIL_ID;
102→    const guardrailVersion = process.env.BEDROCK_GUARDRAIL_VERSION || "DRAFT";
103→
104→    const encoder = new TextEncoder();
105→    const confirmedSession = session;
106→
107→    // Async generator that yields SSE-encoded chunks
108→    async function* makeSSEIterator(): AsyncGenerator<
109→      Uint8Array,
110→      void,
111→      unknown
112→    > {
113→      try {
114→        const generator = streamBedrockResponse({
115→          systemPrompt,
116→          messages,
117→          guardrailId,
118→          guardrailVersion,
119→        });
120→
121→        for await (const chunk of generator) {
122→          if (chunk.type === "text") {
123→            yield encoder.encode(
124→              `data: ${JSON.stringify({ type: "text", content: chunk.text })}\n\n`
125→            );
126→          } else if (chunk.type === "guard") {
127→            yield encoder.encode(
128→              `data: ${JSON.stringify({ type: "guard", action: chunk.action, content: chunk.message })}\n\n`
129→            );
130→          }
131→        }
132→
133→        yield encoder.encode(
134→          `data: ${JSON.stringify({ type: "done" })}\n\n`
135→        );
136→      } catch (error) {
137→        console.error("Bedrock streaming error:", error);
138→
139→        const errorMessage =
140→          error instanceof Error ? error.message : String(error);
141→        if (
142→          errorMessage.includes("guardrail") ||
143→          errorMessage.includes("GUARDRAIL")
144→        ) {
145→          yield encoder.encode(
146→            `data: ${JSON.stringify({
147→              type: "guard",
148→              action: "BLOCKED",
149→              content: `I can only analyze the ${confirmedSession.metadata.totalReviews} ${confirmedSession.metadata.platform} reviews loaded for **${confirmedSession.metadata.productName}**. That question falls outside the scope of the ingested review data. Feel free to ask me anything about the reviews!`,
150→            })}\n\n`
151→          );
152→        } else {
153→          yield encoder.encode(
154→            `data: ${JSON.stringify({
155→              type: "error",
156→              content:
157→                "An error occurred while generating a response. Please try again.",
158→            })}\n\n`
159→          );
160→        }
161→
162→        yield encoder.encode(
163→          `data: ${JSON.stringify({ type: "done" })}\n\n`
164→        );
165→      }
166→    }
167→
168→    const stream = iteratorToStream(makeSSEIterator());
169→
170→    return new Response(stream, {
171→      headers: {
172→        "Content-Type": "text/event-stream; charset=utf-8",
173→        "Cache-Control": "no-cache, no-transform",
174→        Connection: "keep-alive",
175→        "X-Content-Type-Options": "nosniff",
176→      },
177→    });
178→  } catch (error) {
179→    console.error("Chat route error:", error);
180→    return new Response(
181→      JSON.stringify({ error: "Failed to process chat request" }),
182→      { status: 500, headers: { "Content-Type": "application/json" } }
183→    );
184→  }
185→}
