 10→const MAX_CSV_SIZE = 5 * 1024 * 1024; // 5 MB
 11→
 12→export async function POST(request: NextRequest) {
 13→  try {
 14→    // Check Content-Length before parsing body
 15→    const contentLength = parseInt(request.headers.get("content-length") || "0", 10);
 16→    if (contentLength > MAX_CSV_SIZE) {
 17→      return NextResponse.json(
 18→        { success: false, error: `Request too large. Maximum size is ${MAX_CSV_SIZE / 1024 / 1024} MB.` },
 19→        { status: 413 }
 20→      );
 21→    }
 22→
 23→    const body = await request.json();
 24→    const { type, url, csvData, platform = "Amazon" } = body;
 25→
 26→    if (type === "csv" && typeof csvData === "string" && csvData.length > MAX_CSV_SIZE) {
 27→      return NextResponse.json(
 28→        { success: false, error: `CSV data too large. Maximum size is ${MAX_CSV_SIZE / 1024 / 1024} MB.` },
 29→        { status: 413 }
 30→      );
 31→    }
 32→
 33→    let reviews: Review[] = [];
 34→    let productName = "Unknown Product";
 35→    const productUrl = url || "";
 36→    let overallRating: number | undefined;
 37→    let totalGlobalRatings: number | undefined;
 38→    let csvWarnings: string[] = [];
 39→    let csvMapping: ColumnMapping | undefined;
 40→
 41→    if (type === "url" && url) {
 42→      try {
 43→        const result = await scrapeReviews(platform, url);
 44→        reviews = result.reviews;
 45→        productName = result.productName;
 46→        overallRating = result.overallRating;
 47→        totalGlobalRatings = result.totalGlobalRatings;
 48→      } catch (scrapeError) {
 49→        console.warn("Scrape failed:", scrapeError);
 50→        const message = scrapeError instanceof Error ? scrapeError.message : "Automated scraping failed.";
 51→        return NextResponse.json(
 52→          {
 53→            success: false,
 54→            error: message + " You can also try CSV upload instead.",
 55→          },
 56→          { status: 400 }
 57→        );
 58→      }
 59→    } else if (type === "csv" && csvData) {
 60→      const csvResult = parseCSVDetailed(csvData);
 61→      reviews = csvResult.reviews;
 62→      csvWarnings = csvResult.warnings;
 63→      csvMapping = csvResult.mapping;
 64→      productName = body.productName || "Uploaded Product";
 65→
 66→      if (reviews.length === 0) {
 67→        return NextResponse.json(
 68→          {
 69→            success: false,
 70→            error: csvWarnings.length > 0
 71→              ? csvWarnings.join(" ")
 72→              : "No reviews could be extracted. Please check your CSV format.",
 73→            columnMapping: csvMapping,
 74→          },
 75→          { status: 400 }
 76→        );
 77→      }
 78→    } else {
 79→      return NextResponse.json(
 80→        { success: false, error: "Invalid request. Provide URL or CSV data." },
 81→        { status: 400 }
 82→      );
 83→    }
 84→
 85→    if (reviews.length === 0) {
 86→      return NextResponse.json(
 87→        {
 88→          success: false,
 89→          error: "No reviews found. Please check your input and try again.",
 90→        },
 91→        { status: 400 }
 92→      );
 93→    }
 94→
 95→    // Analyze sentiment with Amazon Comprehend
 96→    const enrichedReviews = await analyzeSentiment(reviews);
 97→
 98→    // Compute analytics
 99→    const analytics = computeAnalytics(enrichedReviews);
100→
101→    // Extract date range (sort chronologically via Date parsing)
102→    const dates = enrichedReviews
103→      .map((r) => r.date)
104→      .filter(Boolean)
105→      .sort((a, b) => {
106→        const da = new Date(a).getTime();
107→        const db = new Date(b).getTime();
108→        // If both parse to valid dates, compare numerically
109→        if (!isNaN(da) && !isNaN(db)) return da - db;
110→        // Push unparseable dates to the end
111→        if (isNaN(da)) return 1;
112→        if (isNaN(db)) return -1;
113→        return a.localeCompare(b);
114→      });
115→
116→    const metadata: ReviewMetadata = {
117→      platform,
118→      productName,
119→      productUrl,
120→      totalReviews: enrichedReviews.length,
121→      averageRating: analytics.averageRating,
122→      overallRating,
123→      totalGlobalRatings,
124→      dateRange: {
125→        earliest: dates[0] || "Unknown",
126→        latest: dates[dates.length - 1] || "Unknown",
127→      },
128→      scrapedAt: new Date().toISOString(),
129→    };
130→
131→    // Store session
132→    const sessionId = uuidv4();
133→    const session: ReviewSession = {
134→      sessionId,
135→      reviews: enrichedReviews,
136→      metadata,
137→      analytics,
138→    };
139→    setSession(sessionId, session);
140→
141→    return NextResponse.json({
142→      success: true,
143→      sessionId,
144→      metadata,
145→      reviews: enrichedReviews,
146→      analytics,
147→      reviewCount: enrichedReviews.length,
148→      ...(csvMapping && { columnMapping: csvMapping, csvWarnings }),
149→    });
150→  } catch (error) {
151→    console.error("Ingest error:", error);
152→    return NextResponse.json(
153→      {
154→        success: false,
155→        error: "Failed to process reviews. Please try again.",
156→      },
157→      { status: 500 }
158→    );
159→  }
160→}
