 1→import { ReviewSession } from "@/types";
 2→
 3→// In-memory store for review sessions
 4→// In production, this would be DynamoDB or similar
 5→
 6→interface StoredSession {
 7→  session: ReviewSession;
 8→  lastAccessed: number;
 9→}
10→
11→const SESSION_TTL_MS = 60 * 60 * 1000; // 1 hour
12→const MAX_SESSIONS = 100;
13→
14→const sessions = new Map<string, StoredSession>();
15→
16→/** Remove sessions that have exceeded their TTL */
17→function evictStale(): void {
18→  const now = Date.now();
19→  for (const [id, entry] of sessions) {
20→    if (now - entry.lastAccessed > SESSION_TTL_MS) {
21→      sessions.delete(id);
22→    }
23→  }
24→}
25→
26→/** If we're still over the limit after eviction, drop the oldest */
27→function evictOldest(): void {
28→  if (sessions.size <= MAX_SESSIONS) return;
29→  let oldestId: string | null = null;
30→  let oldestTime = Infinity;
31→  for (const [id, entry] of sessions) {
32→    if (entry.lastAccessed < oldestTime) {
33→      oldestTime = entry.lastAccessed;
34→      oldestId = id;
35→    }
36→  }
37→  if (oldestId) sessions.delete(oldestId);
38→}
39→
40→export function getSession(sessionId: string): ReviewSession | undefined {
41→  const entry = sessions.get(sessionId);
42→  if (!entry) return undefined;
43→
44→  // Check if expired
45→  if (Date.now() - entry.lastAccessed > SESSION_TTL_MS) {
46→    sessions.delete(sessionId);
47→    return undefined;
48→  }
49→
50→  entry.lastAccessed = Date.now();
51→  return entry.session;
52→}
53→
54→export function setSession(sessionId: string, session: ReviewSession): void {
55→  evictStale();
56→  sessions.set(sessionId, { session, lastAccessed: Date.now() });
57→  evictOldest();
58→}
59→
60→export function deleteSession(sessionId: string): boolean {
61→  return sessions.delete(sessionId);
62→}
63→
64→export function hasSession(sessionId: string): boolean {
65→  const entry = sessions.get(sessionId);
66→  if (!entry) return false;
67→  if (Date.now() - entry.lastAccessed > SESSION_TTL_MS) {
68→    sessions.delete(sessionId);
69→    return false;
70→  }
71→  return true;
72→}
